var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"후아, 아슬아슬했네요.","JPN":"ふう、ギリギリでしたね。","ENG":"Whoa, that was close.","TWN":"呼啊，好險啊。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래. 수정을 건지지 못한 건 좀 아쉽지만.","JPN":"そうだな。水晶を持ってこれなかったのはちょっと惜しいが。","ENG":"Tell me about it. Too bad we couldn't recover the crystal.","TWN":"是啊，雖然沒拿到水晶有點可惜。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"저 잔해들을 다시 파헤치면서 찾기엔 시간이 없군. 포기하는 수밖에.","JPN":"あの残骸を探って見つけるには時間がないな。諦めるしかない。","ENG":"We don't have enough time to dig through the rubble. I guess we'll just have to do without it.","TWN":"沒時間從那些殘骸裡尋找了，只能放棄。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그보다 꼬맹이 너, 나오기 직전에 뭐 하고 있었던 거야.","JPN":"それよりガキ、出る直前に何してたんだ。","ENG":"By the way, kid. What were you doing in there before we ran?","TWN":"話說回來，小鬼，出來之前你在做什麼。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"넹? 저 계속 리타 언니 뒤에 있었는데요?","JPN":"え？　私はずっとリタお姉ちゃんの後ろにいましたよ？","ENG":"Huh? I was right behind you.","TWN":"嗯？我一直都在麗塔姐姐身後啊。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아니. 한창 싸우고 있을 때 갑자기 내 옆에서 사라졌어.","JPN":"いや、戦っている最中に急に私の傍から消えた。","ENG":"Yeah, right. I know you disappeared while I was fighting.","TWN":"不。在我打架的時候你突然消失了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"네 말대로 얌전히 뒤에 있었으면 부를 일도 없었겠지.","JPN":"本当に大人しく後ろにいたなら呼ぶこともなかっただろ。","ENG":"I wouldn't have had to call for you if you were right behind me.","TWN":"如果按你說的有乖乖在我身後，那我就不會喊你了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"정말이에요! 총알이 막 날아와서 정신 없긴 했지만 꼭 붙어 있었는걸요!","JPN":"本当ですよ！　銃弾が飛び交ってバタバタしていたけど、ちゃんとくっついていましたよ！","ENG":"I swear! Things got a bit hectic with all the bullets flying our way, but I stuck right behind you!","TWN":"真的！雖然子彈飛來飛去，但我真的一直都緊緊跟著你！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......그럼 방금 네 품에서 굴러 떨어진 그 수정은 뭔지 설명해 봐.","JPN":"……それじゃあ、今お前の服の中から転がり落ちたその水晶は何なのか説明してみろ。","ENG":"Then you'd better explain how you got your hands on that crystal you're trying to hide.","TWN":"……那剛才從你懷裡掉下來的水晶是怎麼回事，你解釋一下。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"어, 어라? 이럴 리가 없는데? 언제 챙겼지?","JPN":"あ、あれ？　これは何でしょう？　いつ持ってきたんだろう？","ENG":"H-huh? What's going on? I never took this!","TWN":"呃，哎呀？怎麼可能？我是什麼時候拿的？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"알았다! 수정에 발이 달렸나 봐요!","JPN":"わかった！　水晶に足が生えていたかもしれません！","ENG":"Alright, then! The crystal must have feet!","TWN":"我知道了！是水晶有長了腳！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"안 달렸어.","JPN":"そんなの付いてないぞ。","ENG":"It doesn't.","TWN":"並沒有長腳。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"하아...... 이미 가져와 버렸는데 이걸 혼낼 수도 없고......","JPN":"はあ……もう持って来たものを怒っても無駄だな……","ENG":"Ugh... I guess it's too late to scold you for bringing this...","TWN":"唉……拿都拿了，唸你有什麼用呢……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"헤헤, 어떻게 된 일인지는 몰라도 빈손으로 돌아가지 않아서 다행이네요.","JPN":"ヘヘッ、どういう訳かわからないけど、手ぶらで帰らずに済んでよかったです。","ENG":"Heh, I'm still not sure what happened, but at least we won't have to go back empty-handed.","TWN":"嘿嘿，雖然不知道是怎麼一回事，但總算不是空手而歸啊。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"맞다. 그래도 지진을 일으킨 건 심했어요, 언니.","JPN":"そうだ。とはいえ、地震を起こしたのはやりすぎですよ。","ENG":"Speaking of which. That earthquake was overkill, Rita.","TWN":"對了，引起地震確實有點過分了吧，姐姐。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"저희 둘 다 납작 오징어가 될 뻔했잖아요.","JPN":"私たち二人ともがれきの下敷きになりかけたんですから。","ENG":"You almost squashed us too.","TWN":"我們兩個差點就變成鐵板魷魚了呢。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"무슨 소리야. 내가 그런 무모한 짓을 왜 해.","JPN":"何言ってるんだ？　私がそんな無謀なことをするわけないだろ。","ENG":"What are you talking about? I wouldn't do anything so reckless.","TWN":"胡說什麼，我怎麼會做那種魯莽的事。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그러면 방금 전에 있던 지진은 그냥 우연이었던 거예요?","JPN":"それじゃあ、さっきの地震は偶然だったんですか？","ENG":"You mean that earthquake was just a coincidence?","TWN":"那之前那個地震只是偶然嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래. 공교롭게 시기가 맞아떨어졌던 거겠지.","JPN":"そう。あいにくタイミングが合っただけさ。","ENG":"Yes. The timing was just uncanny.","TWN":"嗯，可能就是恰巧吧。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"위쪽에 연락해. 금방 돌아간다고.","JPN":"上に連絡しろ。今すぐ戻るとな。","ENG":"Call the folks upstairs. Tell them we're on our way.","TWN":"聯繫上面，說我們馬上回去。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"이상하다......? 이 주파수가 아니었나?","JPN":"おかしいな……この周波数だったと思うけど……？","ENG":"It's not working. Am I on the wrong frequency?","TWN":"奇怪……？難道不是這個頻率？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"침식파 때문에 전파가 잘 안 잡힐 수도 있어. 감도를 높여 봐.","JPN":"侵食波のせいで電波がうまく拾えない時もある。感度を上げてみろ。","ENG":"The Corruption Ray might be jamming the signals. Try cranking it up.","TWN":"可能因為侵蝕波的關係捕捉不到信號，提高靈敏度試試。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"<color=#ffd34c>......복한다!</color>","JPN":"<color=#ffd34c>……する！</color>","ENG":"<color=#ffd34c>—peat!</color>","TWN":"<color=#ffd34c>……複！</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BATTLEFIELD"},{"id":"L36_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"<color=#ffd34c>이, 이 구조 요청은 관리국이 지정한 단파 회선을 통해 송신하고 있다!</color>","JPN":"<color=#ffd34c>こ、この救助要請は管理局が指定した短波回線から送信している！</color>","ENG":"<color=#ffd34c>Th-this May Day is relayed through the shortwave line designated by the Administration!</color>","TWN":"<color=#ffd34c>這、這個求救信號正在通過管理局指定的短波線路發送！</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"<color=#ffd34c>3종 침식체와 조우했어! 제발, 우리만으로는 대응할 수가......!</color>","JPN":"<color=#ffd34c>第3種侵食体と遭遇した！　どうか、私たちでは対応でき……！</color>","ENG":"<color=#ffd34c>We've encountered a Category 3! Please... We won't stand a chance on our own!</color>","TWN":"<color=#ffd34c>遇到了3類侵蝕體！拜託了，單憑我們無法應對……！</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니, 이 무전......?","JPN":"リタお姉ちゃん、この無線は……？","ENG":"Did you hear that, Rita?","TWN":"麗塔姐姐，這個無線……？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L44_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그 대장이란 녀석 목소리야. 하여튼 믿고 맡길 놈이 없군.","JPN":"あの隊長の声だ。まったく、安心して任せられる奴がいないな。","ENG":"It's that Captain of theirs. I just can't count on anyone here, can I?","TWN":"是那個隊長的聲音，真是沒一個讓人放心的。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"내 손 잡아! 지상까지 날아간다!","JPN":"手を握れ！　地上まで飛んでいく！","ENG":"Grab my hand! We'll fly back up to surface!","TWN":"抓住我的手！飛到地面！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_FLY"},{"id":"L49_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니, 저기 보세요! 수송선 방향에 사람들이 있어요!","JPN":"リタお姉ちゃん、あそこを見てください！　輸送船方向に傭兵団の人がいます！","ENG":"Look over there, Rita! There are people near the ship!","TWN":"麗塔姐姐！看那邊！運輸船方向有人！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"RITA_HORIZON_NULL_ON","text":{"KOREA":"그새 쑥대밭이 됐군. 호라이즌은 왜 연락하지 않은 거지?","JPN":"めちゃくちゃだな。ホライズンはなぜ連絡しなかったんだ？","ENG":"Something flattened this place before we could get here. Why didn't Horizon get in touch with us?","TWN":"一會功夫就成廢墟了。地平線為什麼沒有聯繫我們呢？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"지원은 아직이야, 대장?! 이러다 우리 전부 죽겠어!","JPN":"隊長、応援はまだか？　このままじゃ全滅するぞ！","ENG":"When's the cavalry coming, Captain? We're all going to die at this rate!","TWN":"支援還沒到嗎，隊長？！這樣下去我們都會死在這裡的！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"시끄러워! 나도 지금 필사적이라고! 누군 안 무서운 줄 알아?!","JPN":"うるせぇ！　俺だって必死なんだ！　ヤバい状況ってぐらい、わかってる！","ENG":"Shut up! I'm busting my ass here too! You ain't the only one who's scared here!","TWN":"閉嘴！我也在全力以赴！你以為我不害怕嗎？！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"아, 아무라도 좋으니까......! 빨리 와 줘!! 죽고 싶지 않아!!","JPN":"だ、誰でもいいから……！　早く来てくれ！！　死にたくねえんだよ！！","ENG":"Come on... anyone will do... Just come help us already! I don't want to die!","TWN":"誰、誰能來……！救救我們！！我不想死！！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L14_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"대장님! 괜찮으세요?!","JPN":"隊長！　大丈夫ですか！？","ENG":"Captain! Are you okay?!","TWN":"隊長！您沒事吧？！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L15_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"무슨 일이 있었던 거지? 어서 말해.","JPN":"何があったんだ？　さっさと教えろ。","ENG":"What happened? Speak.","TWN":"發生了什麼事？快說。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"그, 그게...... 우린 그냥...... 돌아가려고 했을 뿐인데...... 그런 것뿐인데......!","JPN":"そ、それが……俺らはただ戻ろうとしただけなのに……それだけなのに……！","ENG":"W-well... We were just... trying to go back... That's all we did!","TWN":"那，那個……我們只是……想回去而已……只是這樣而已……！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"맞아, 모르스야!","JPN":"そうだ、モールスだ！","ENG":"Right, it was Mors!","TWN":"果然沒錯，一定就是莫爾斯！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"그 녀석이 저 괴물을 불러들인 거라고! 재난을 부른다는 소문이 정말이었어!","JPN":"あいつがあの化物を呼び出したんだ！　災いをもたらすという噂は本当だったんだ！","ENG":"She must have summoned that monster! It's true what they say! She really is the bringer of disaster!","TWN":"一定是那傢伙把怪物叫來的！他會招來災難的傳聞都是真的！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"정신 차려!","JPN":"落ち着け！","ENG":"Wake up!","TWN":"清醒一點！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_WHIP_02_END"},{"id":"L23_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"......!","JPN":"……！","ENG":"......!","TWN":"……！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"수송선은 아직 멀쩡해. 살아서 돌아가고 싶으면 정신 차려.","JPN":"輸送船はまだ平気だ。生きて帰りたければ、しっかりしろ。","ENG":"The ship is still intact. You'd better get frosty if you want to make it out alive.","TWN":"運輸船還很完好。如果想活著回去就給我打起精神。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"부하들을 소집시켜. 저 괴물은 내가 막는다.","JPN":"部下を集めろ。あの化物は私が止める。","ENG":"Gather all your men. I'll stop the monster.","TWN":"把你的人都召集起來，我來抵擋那個怪物。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"아, 알겠습니다!","JPN":"わ、わかりました！","ENG":"R-roger!","TWN":"啊，我知道了！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"타이런트라...... 골치 아프게 됐군.","JPN":"タイラントか……厄介なことになったな。","ENG":"A Tyrant, huh... This can't be good.","TWN":"3類侵蝕體「暴君」……有點麻煩了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"꼬맹이, 이번에는 지켜 주기 힘들지도 몰라.","JPN":"ガキ、今回は守ってやる余裕がないかもしれない。","ENG":"Kid, I might not be able to protect you this time.","TWN":"小鬼，這次我可能無法照顧你了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"걱정 마세요, 언니! 저도 열심히 도울게요!","JPN":"心配しないでください、リタお姉ちゃん！　私も全力で手伝います！","ENG":"Don't worry, Rita! I'll do my best to help!","TWN":"別擔心，姐姐！我會盡力幫你的！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};